+/** A small transaction buffer used while a query result is being updated. */
+export class DeferredController {
+    private scopes: Command[][] = [[]];
+    private executing = false;
+    readonly api: DeferredWorld;
+
+    constructor(private readonly world: World) {
+        this.api = {
+            spawn: (...traits) => {
+                // Allocate now so subsequent deferred commands can refer to the entity. Its
+                // traits are still deferred, and query results are snapshots, so it cannot
+                // enter the iteration which created it.
+                const entity = createEntity(world);
+                this.current.push({ type: 'spawn', entity, traits });
+                return entity;
+            },
+            destroy: (entity) => this.current.push({ type: 'destroy', entity }),
+            add: (entity, ...traits) => this.current.push({ type: 'add', entity, traits }),
+            remove: (entity, ...traits) => this.current.push({ type: 'remove', entity, traits }),
+            addExclusive: (entity, ...traits) =>
+                this.current.push({ type: 'exclusive', entity, traits }),
+            flush: () => this.flush(),
+        };
+    }
+
+    private get current() {
+        return this.scopes[this.scopes.length - 1];
+    }
+
+    enter() {
+        this.scopes.push([]);
+    }
+
+    exit() {
+        this.flush();
+        this.scopes.pop();
+    }
+
+    flushForMutation() {
+        if (!this.executing && this.current.length) this.flush();
+    }
+
+    flush() {
+        const commands = this.current;
+        if (!commands.length || this.executing) return;
+        this.scopes[this.scopes.length - 1] = [];
+        this.executing = true;
+        try {
+            // A spawned entity which is destroyed in the same transaction has never become
+            // observable. Drop its pending work and release the reservation.
+            const cancelled = new Set<Entity>();
+            const spawned = new Set<Entity>();
+            for (const command of commands) {
+                if (command.type === 'spawn') spawned.add(command.entity);
+                else if (command.type === 'destroy' && spawned.has(command.entity)) cancelled.add(command.entity);
+            }
+
+            for (const command of commands) {
+                if (cancelled.has(command.entity)) {
+                    if (command.type === 'destroy' && this.world.has(command.entity)) destroyEntity(this.world, command.entity);
+                    continue;
+                }
+                if (!this.world.has(command.entity)) continue;
+                if (command.type === 'spawn') {
+                    command.entity.add(...command.traits);
+                } else if (command.type === 'destroy') {
+                    if (command.entity === this.world[$internal].worldEntity) {
+                        throw new Error('Koota: The world entity cannot be destroyed through deferred commands.');
+                    }
+                    destroyEntity(this.world, command.entity);
+                } else if (command.type === 'add') {
+                    this.add(command.entity, command.traits);
+                } else if (command.type === 'remove') {
+                    command.entity.remove(...command.traits);
+                } else {
