+            if (command.entity !== entity) continue;
+            if (command.type === 'destroy') value = false;
+            if (command.type === 'add' || command.type === 'spawn') {
+                for (const config of command.traits) {
+                    if (config === trait || (!isRelationPair(config) && !isRelationPair(trait) && (Array.isArray(config) ? config[0] : config) === trait)) value = true;
+                }
+            }
+            if (command.type === 'remove') {
